tasks.solution:
#include <iostream>

int main() {
    int n;
    if (!(std::cin >> n)) return 0;
    int sum = 0;
    for (int i = 1; i <= n; i++) {
        if (i % 2 == 0) {
            sum += i;
        }
    }
    std::cout << sum << std::endl;
    return 0;
}

