tasks.solution:
#include <iostream>

int main() {
    int n;
    if (!(std::cin >> n)) return 0;
    long long factorial = 1;

    while (n > 0) {
        factorial *= n;
        n--;
    }

    std::cout << factorial << std::endl;
    return 0;
}

