tasks.solution:
#include <iostream>

int main() {
    int n;
    if (!(std::cin >> n)) return 0;

    for (int i = n; i > 0; i--) {
        std::cout << i << " ";
    }

    std::cout << "BLAST OFF!" << std::endl;
    return 0;
}
